CREATE POLICY "scan_photos_select_own" ON storage.objects FOR SELECT TO authenticated USING (bucket_id = 'scan-photos' AND auth.uid()::text = (storage.foldername(name))[1]);
CREATE POLICY "scan_photos_insert_own" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'scan-photos' AND auth.uid()::text = (storage.foldername(name))[1]);
CREATE POLICY "scan_photos_delete_own" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'scan-photos' AND auth.uid()::text = (storage.foldername(name))[1]);